from confluent_kafka import Producer

conf = {'bootstrap.servers': 'broker1:9092,broker2:9092', 'linger.ms': 5, 'batch.size': 65536}
p = Producer(conf)

def delivery_report(err, msg):
    if err:
        print('Delivery failed:', err)
    else:
        print('Delivered message to', msg.topic(), msg.partition(), msg.offset())

for i in range(1000):
    p.produce('user-activity', key=str(i % 100), value='event_payload_%d' % i, callback=delivery_report)

p.flush()

